class Solution:
    def minPatches(self, nums: List[int], n: int) -> int:
        patches, miss, i = 0, 1, 0
        while miss <= n:
            if i < len(nums) and nums[i] <= miss:
                miss += nums[i]; i += 1
            else:
                miss += miss; patches += 1
        return patches

